import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.DXGyWiRo.js";const o="/media/202402//1709021960.850464.png",n="/media/202402//1709021960.8708622.png",l="/media/202402//1709021960.8891733.png",i="/media/202402//1709021960.9028091.png",s="/media/202402//1709021960.9070773.png",h="/media/202402//1709021960.9294753.png",p="/media/202402//1709021960.9338431.png",S=JSON.parse('{"title":"RK3588 一体机多模态产品规格书","description":"","frontmatter":{"title":"RK3588 一体机多模态产品规格书"},"headers":[],"relativePath":"hardware/rk3588-mm/specs.md","filePath":"hardware/rk3588-mm/specs.md","lastUpdated":null}'),m={name:"hardware/rk3588-mm/specs.md"};function g(c,t,u,A,b,I){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="产品规格书" tabindex="-1">产品规格书 <a class="header-anchor" href="#产品规格书" aria-label="Permalink to &quot;产品规格书&quot;">​</a></h1><p><strong>目 录</strong></p><ol><li>产品概述</li><li>产品实物图</li><li>适用范围</li><li>产品特点</li><li>产品功能说明</li><li>接口描述</li><li>硬件尺寸信息</li><li>整机规格参数</li><li>电气特性参数</li></ol><h1 id="离线资料下载" tabindex="-1">离线资料下载 <a class="header-anchor" href="#离线资料下载" aria-label="Permalink to &quot;离线资料下载&quot;">​</a></h1><p>RK3588s AIUI多模态套件开发资料（产品规格书、使用手册），可以点击下载: <a href="/media/attachment/2026/01/RK3588s_AIUI%E5%A4%9A%E6%A8%A1%E6%80%81%E5%A5%97%E4%BB%B6%E4%BA%A7%E5%93%81%E8%B5%84%E6%96%99.zip">【附件】RK3588s AIUI多模态套件产品资料.zip</a></p><h1 id="产品概述" tabindex="-1">产品概述 <a class="header-anchor" href="#产品概述" aria-label="Permalink to &quot;产品概述&quot;">​</a></h1><p>RK3588 AIUI多模态交互产品是一款基于多麦克风阵列+图像识别的整体语音解决方案。芯片采用的是瑞芯微RK3588，8nm生产工艺的8核CPU（四核Cortex-A76 的 CPU，频率最高 2.4GHz ；四核Cortex-A55的CPU，频率最高 1.8GHz）。接口方面集成千兆以太网、HDMI、HDMI IN、RS232 串口、RS485、USB3.0、USB2.0、TypeC(DP)。本产品集成神经网络处理器 NPU，算力高达6.0Tops，兼容多种 AI框架，可灵活应用于各种智能产品。</p><h1 id="产品实物图" tabindex="-1">产品实物图 <a class="header-anchor" href="#产品实物图" aria-label="Permalink to &quot;产品实物图&quot;">​</a></h1><p><img src="'+o+'" alt="3588主机图片" title="null"></p><p>图1 RK3588 AIUI多模态交互产品主机</p><h1 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h1><p>RK3588 AIUI多模态交互产品方案广泛适用于集群服务器、高性能计算/存储、计算机视觉、边缘计算、商显一体设备、医疗健康设备、自动售货机、工业设备等 AI 应用领域。</p><h1 id="产品特点" tabindex="-1">产品特点 <a class="header-anchor" href="#产品特点" aria-label="Permalink to &quot;产品特点&quot;">​</a></h1><ul><li><strong>高性能四+四大小核处理器</strong></li></ul><p>采用RK3588系列，标准6Tops 算力</p><ul><li><strong>产品长时间稳定运行，具有高可靠性</strong></li></ul><p>大风扇散热，高效降温。60℃高温老化 7x24 小时稳定运行</p><ul><li><strong>工业级外观的外观设计</strong></li></ul><p>外表美观大气、多种安装方式、隐蔽式引线孔</p><ul><li><strong>多种网络连接方式</strong></li></ul><p>支持千兆以太网（RJ45）</p><ul><li><strong>串口通讯连接</strong></li></ul><p>支持 RS232*2</p><ul><li><strong>操作系统</strong></li></ul><p>操作系统：Linux/Android，支持 Android 系统定制，提供系统调用接 API 参考代码</p><ul><li><strong>配置4-8麦克风阵列板</strong></li></ul><p>可配置近场麦克风阵列板，支持 4-8 个模拟麦、支持关键词唤醒、回声消噪、VAD（端点检测）(VoiceActivation Detection)和声源定位等功能，大大提升了语音识别的精度与准确性。</p><h1 id="产品功能说明" tabindex="-1">产品功能说明 <a class="header-anchor" href="#产品功能说明" aria-label="Permalink to &quot;产品功能说明&quot;">​</a></h1><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>功能</strong></td><td><strong>特性</strong></td></tr><tr><td>录制音频</td><td>支持线性4~8麦 5米远场录音</td></tr><tr><td>回声消除</td><td>回声消除-25dB</td></tr><tr><td>前端降噪</td><td>噪声抑制-10dB</td></tr><tr><td>人脸唤醒</td><td>检测唇形，免语音唤醒，人脸检测准确率达 99.99%</td></tr><tr><td>在线识别</td><td>支持中英文和方言识别</td></tr><tr><td>语义理解</td><td>提供 100 多个官方技能，支持自定义技能</td></tr><tr><td>语音合成</td><td>支持中英文和方言合成</td></tr><tr><td>串口通信</td><td>支持串口发送指令给上位机</td></tr></tbody></table><p>表1 RK3588 AIUI多模态交互产品功能说明表</p><h1 id="接口描述" tabindex="-1">接口描述 <a class="header-anchor" href="#接口描述" aria-label="Permalink to &quot;接口描述&quot;">​</a></h1><p><img src="'+n+'" alt="3588主机图片" title="null"></p><p>图2 RK3588 AIUI多模态交互产品接口</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>编号</strong></td><td><strong>接口名称</strong></td><td><strong>说明</strong></td></tr><tr><td>LAN</td><td>网口</td><td>千M以太网</td></tr><tr><td>DC-12V</td><td>电源输入接口</td><td>DC12V3A，DC5.5-2.1</td></tr><tr><td>USB3.0/USB2.0</td><td>USB接口</td><td>USB3.0 * 2，USB2.0 * 4</td></tr><tr><td>USB3.0/USB2.0接口之间</td><td>复位按键</td><td>外部插针按住上电进入刷机模式</td></tr><tr><td>Type-C</td><td>ADB/DP接口</td><td>Typec接口，连接电脑OTA或调试</td></tr><tr><td>HDMI</td><td>HDMI接口</td><td>HDMI 2.1接口 * 1 可最高输出8K 60Hz，HDCP2.3</td></tr><tr><td>MicArray</td><td>麦克风接口</td><td>支持八路麦克风输入</td></tr><tr><td>REF</td><td>耳机口</td><td>音频/回采输入</td></tr><tr><td>SPEAKER</td><td>喇叭口</td><td>连接8Ω5W * 2 ，喇叭输出 4pin 2.0mm</td></tr><tr><td>HPOUT</td><td>Line out口</td><td>音频输出</td></tr><tr><td>RS232</td><td>RS232</td><td>RS232 * 2，串口通讯</td></tr></tbody></table><p>表2 RK3588 AIUI多模态交互产品主机接口说明（从右到左）</p><h1 id="硬件尺寸信息" tabindex="-1">硬件尺寸信息 <a class="header-anchor" href="#硬件尺寸信息" aria-label="Permalink to &quot;硬件尺寸信息&quot;">​</a></h1><p><img src="'+l+'" alt="" title="null"></p><p>图3 RK3588 AIUI多模态交互产品主板尺寸图，210*150（单位mm）</p><p><img src="'+i+'" alt="C:/Users/fjyu2/Desktop/3588外壳尺寸.png3588外壳尺寸" title="null"></p><p>图4 RK3588 AIUI多模态交互产品主机尺寸图，250<em>170</em>47（单位mm）</p><p><img src="'+s+'" alt="ae2309750452c1df400a69a169242af" title="null"></p><p>图5 四麦麦克风板尺寸图(单位mm)</p><p><strong>PS</strong>:麦克风板安装到设备上时，设备上需要预留麦克风的孔洞，规格是直径11mm,深度0.5mm；且需要配φ11mm 厚度1mm的硅胶垫+防尘网（双面可粘贴），中间直径2mm 。</p><p><img src="'+h+'" alt="500W单目摄像头" title="null"></p><p>图6 单目500W远焦摄像头尺寸图(单位mm)【可选1】</p><p><img src="'+p+'" alt="" title="null"></p><p>图7 双目500W远焦摄像头尺寸图(单位mm) 【可选2】</p><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>配件名称</strong></td><td><strong>数量</strong></td><td><strong>线束长度</strong></td><td><strong>备注</strong></td></tr><tr><td>双目摄像头USB线</td><td>2</td><td>2.5m</td><td>带卡扣屏蔽,根据已选多模态摄像头规格配置</td></tr><tr><td>单目摄像头USB线</td><td>1</td><td>2m</td><td>不带卡扣，根据已选多模态摄像头规格配置</td></tr><tr><td>三段式音频线</td><td>2</td><td>1.5m</td><td>三段式音频线</td></tr><tr><td>Type-C连接线</td><td>1</td><td>1.5m</td><td></td></tr><tr><td>RS232转USB线</td><td>1</td><td>0.8m</td><td></td></tr><tr><td>20p18线音频线</td><td>1</td><td>2.5m</td><td>带屏蔽麦克风阵列线, 20pin 18根线</td></tr><tr><td>电源适配器</td><td>1</td><td>1.5m</td><td>墙插式电源适配器，12V2A，插头5521，过认证</td></tr></tbody></table><p>表3 RK3588 AIUI多模态交互产品配套线束信息表</p><h1 id="整机规格参数" tabindex="-1">整机规格参数 <a class="header-anchor" href="#整机规格参数" aria-label="Permalink to &quot;整机规格参数&quot;">​</a></h1><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>编号</strong></td><td><strong>接口名称</strong></td><td><strong>说明</strong></td></tr><tr><td>1</td><td>CPU</td><td>RK3588 Octo-core, Cortex-A76 and Cortex-A55频率高达2.4GHz</td></tr><tr><td>2</td><td>GPU</td><td>Mali-G610 GPU，OpenGL ES 1.1/2.0/3.2，OpenCL 2.2，Vulkan 1.2内嵌高性能2D加速硬件</td></tr><tr><td>3</td><td>DDR</td><td>LPDDR4X 8G(4G/8G/16G可选)</td></tr><tr><td>4</td><td>NPU</td><td>6.0 Tops</td></tr><tr><td>5</td><td>OS</td><td>Android 12(Ubuntu/Linux 可选)</td></tr><tr><td>6</td><td>内置存储器</td><td>支持 eMMC5.1 ，64G(16GB/32GB/64G/128G可选）</td></tr><tr><td>7</td><td>显示输出</td><td>HDMI 2.1接口 * 1，可最高输出8K 60Hz，HDCP2.3 DP接口 * 1，4Lane，可最高输出8K 30Hz，HDCP2.3</td></tr><tr><td>8</td><td>HDMI Input</td><td>最高支持4K 60HZ</td></tr><tr><td>9</td><td>以太网</td><td>1000M</td></tr><tr><td>10</td><td>WIFI</td><td>无线网络接入 IEEE 802.11a/b/g/n/ac MIMO</td></tr><tr><td>11</td><td>定时时钟</td><td>支持RTC</td></tr><tr><td>12</td><td>USB</td><td>USB3.1 HOST A型 * 1 USB3.0 HOST A型 * 1 USB3.1 OTG Type-C * 1 USB2.0 HOST HOST A型 * 4</td></tr><tr><td>13</td><td>PCIE</td><td>PCIE3.0 M.2 M-Key</td></tr><tr><td>14</td><td>Audio</td><td>模块阵型：平行阵元个数：8 个 阵元尺寸：35*8mm 唤醒距离：&lt; 20m 识别距离：&lt; 5m 信噪比：SNR &gt; 63dB 工作温度：-20°C~80°C 声源定位：水平 360° 定位精度：±12° 支持关键词唤醒、声源定位、噪声抑制、VAD（端点检测）</td></tr><tr><td>15</td><td>摄像头模组</td><td>500W 双彩色摄像头</td></tr><tr><td>16</td><td>工业接口</td><td>RS232接口 * 2</td></tr><tr><td>17</td><td>输入电压范围</td><td>DC9~14V 推荐工作电压 DC12V</td></tr><tr><td>18</td><td>工作电流</td><td>裸板典型值0.2A 最大值0.25A</td></tr><tr><td>19</td><td>工作环境</td><td>-10~75° 相对湿度≤80%</td></tr><tr><td>20</td><td>外形尺寸</td><td>250 * 170 * 45mm</td></tr><tr><td>21</td><td>开机启动时间</td><td>12S</td></tr><tr><td>22</td><td>扬声器最大功率</td><td>双 5W 8Ω</td></tr></tbody></table><p>表4 RK3588 AIUI多模态交互产品主机规格参数</p><h1 id="电气特性参数" tabindex="-1">电气特性参数 <a class="header-anchor" href="#电气特性参数" aria-label="Permalink to &quot;电气特性参数&quot;">​</a></h1><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>符号</strong></td><td><strong>参数</strong></td><td><strong>测试条件</strong></td><td><strong>最小值</strong></td><td><strong>典型值</strong></td><td><strong>最大值</strong></td><td><strong>单位</strong></td></tr><tr><td>VCC</td><td>工作电压</td><td>裸板</td><td>9</td><td>12</td><td>12</td><td>V</td></tr><tr><td>VIN</td><td>工作电流</td><td>裸板</td><td>0.12</td><td>0.20</td><td>0.25</td><td>A</td></tr><tr><td>工作环境</td><td>工作温度</td><td>裸板</td><td>-10</td><td>25</td><td>75</td><td>℃</td></tr><tr><td>相对湿度</td><td>\\</td><td>\\</td><td>\\</td><td>80%</td><td>\\</td><td></td></tr></tbody></table><p>表5 RK3588 AIUI多模态交互产品主机电气特性参数</p>',55)])])}const P=d(m,[["render",g]]);export{S as __pageData,P as default};
